html = "<!DOCTYPE html>\n<html>\n<head>\n<meta charset=\"UTF-8\" />\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\n<style>\n:root{\n  --bg:#070910;\n  --panel:#101623;\n  --panel2:#121a29;\n  --cell:#151c28;\n  --cell2:#182130;\n  --grid:#3a4252;\n  --gold:#d8b05c;\n  --text:#edf1f7;\n  --muted:#96a0b2;\n  --green:#126a42;\n  --green2:#20a96b;\n  --purple:#352a54;\n  --pink:#d95772;\n  --blue:#61c8e8;\n  --mint:#47e6a0;\n}\n*{box-sizing:border-box}\nhtml,body{\n  margin:0;\n  min-height:100%;\n  color:var(--text);\n  font-family:Inter,ui-sans-serif,system-ui,\"Segoe UI\",Arial,sans-serif;\n  overflow-x:hidden;\n  background:\n    radial-gradient(circle at 50% -8%, rgba(216,176,92,.10), transparent 24%),\n    radial-gradient(circle at 12% 35%, rgba(97,200,232,.055), transparent 18%),\n    radial-gradient(circle at 88% 32%, rgba(217,87,114,.045), transparent 20%),\n    linear-gradient(180deg,#090b12 0%,#05060a 100%);\n}\n.app{\n  position:relative;\n  width:min(94vw,610px);\n  margin:0 auto;\n  padding:10px 8px 24px;\n  z-index:2;\n}\n\n/* nicer themed background: aircraft trails + tiny bingo cards */\n.sky-item{\n  position:fixed;\n  pointer-events:none;\n  z-index:0;\n  opacity:.22;\n}\n.plane{\n  width:42px;height:18px;\n  animation:planeDrift 9s ease-in-out infinite alternate;\n  filter:drop-shadow(0 0 8px rgba(97,200,232,.18));\n}\n.plane svg{width:100%;height:100%;stroke:rgba(97,200,232,.62);fill:none;stroke-width:2.2;stroke-linecap:round;stroke-linejoin:round}\n.trail{\n  position:fixed;\n  width:90px;height:1px;\n  background:linear-gradient(90deg,transparent,rgba(216,176,92,.22),transparent);\n  transform:rotate(-10deg);\n  animation:trailPulse 4s ease-in-out infinite alternate;\n}\n.mini-bingo{\n  width:34px;height:34px;\n  border:1px solid rgba(216,176,92,.24);\n  background:\n    linear-gradient(90deg,transparent 31%,rgba(216,176,92,.16) 32% 35%,transparent 36% 64%,rgba(216,176,92,.16) 65% 68%,transparent 69%),\n    linear-gradient(0deg,transparent 31%,rgba(216,176,92,.16) 32% 35%,transparent 36% 64%,rgba(216,176,92,.16) 65% 68%,transparent 69%),\n    rgba(16,23,37,.42);\n  animation:bingoFloat 8s ease-in-out infinite alternate;\n}\n.cloud{\n  color:rgba(237,241,247,.20);\n  font-weight:900;\n  font-size:20px;\n  letter-spacing:.08em;\n  animation:cloudFloat 10s ease-in-out infinite alternate;\n}\n.p1{left:6vw;top:22vh}\n.p2{right:8vw;top:31vh;animation-delay:1.4s}\n.p3{left:12vw;bottom:18vh;animation-delay:2.2s}\n.t1{left:8vw;top:26vh}\n.t2{right:10vw;top:35vh;animation-delay:1.4s}\n.b1{right:13vw;bottom:21vh;animation-delay:.9s}\n.b2{left:5vw;top:58vh;animation-delay:2.4s}\n.c1{right:6vw;top:60vh}\n.c2{left:7vw;bottom:10vh;animation-delay:2s}\n\n@keyframes planeDrift{\n  from{transform:translate(0,0) rotate(-7deg);opacity:.15}\n  to{transform:translate(18px,-24px) rotate(5deg);opacity:.42}\n}\n@keyframes trailPulse{\n  from{opacity:.08;transform:translateX(0) rotate(-10deg)}\n  to{opacity:.28;transform:translateX(16px) rotate(-10deg)}\n}\n@keyframes bingoFloat{\n  from{transform:translateY(0) rotate(-4deg);opacity:.12}\n  to{transform:translateY(-22px) rotate(5deg);opacity:.38}\n}\n@keyframes cloudFloat{\n  from{transform:translateY(0);opacity:.10}\n  to{transform:translateY(-14px);opacity:.25}\n}\n\n/* header */\n.header{text-align:center;margin:4px auto 8px}\n.logo-card{\n  display:inline-block;\n  padding:9px 18px 11px;\n  background:rgba(11,15,23,.50);\n  border:1px solid rgba(216,176,92,.14);\n  box-shadow:0 12px 34px rgba(0,0,0,.26), inset 0 0 24px rgba(255,255,255,.018);\n}\n.title{\n  color:var(--gold);\n  font-size:clamp(30px,5.4vw,48px);\n  font-weight:950;\n  letter-spacing:-.055em;\n  line-height:.94;\n  text-shadow:0 0 13px rgba(216,176,92,.22);\n  animation:titleSoft 4.2s ease-in-out infinite;\n}\n.title span{\n  display:block;\n  font-size:.64em;\n  margin-top:.08em;\n}\n@keyframes titleSoft{\n  0%,100%{filter:brightness(.96)}\n  50%{filter:brightness(1.13)}\n}\n\n/* toolbar */\n.toolbar{\n  width:max-content;\n  max-width:100%;\n  margin:0 auto 10px;\n  padding:5px;\n  display:flex;\n  gap:5px;\n  align-items:center;\n  background:rgba(13,17,26,.92);\n  border:1px solid rgba(255,255,255,.08);\n  box-shadow:0 10px 24px rgba(0,0,0,.28);\n}\n.icon-btn{\n  width:34px;height:34px;\n  border:1px solid rgba(216,176,92,.35);\n  background:#111722;\n  color:var(--gold);\n  cursor:pointer;\n  display:grid;\n  place-items:center;\n  transition:transform .14s ease,box-shadow .14s ease,filter .14s ease,border-color .14s ease;\n}\n.icon-btn svg{width:18px;height:18px;stroke:currentColor;fill:none;stroke-width:2.4;stroke-linecap:round;stroke-linejoin:round}\n.icon-btn:hover{\n  transform:translateY(-1px);\n  filter:brightness(1.15);\n  border-color:var(--gold);\n  box-shadow:0 0 14px rgba(216,176,92,.18);\n}\n.icon-btn:active{transform:scale(.96)}\n.board-select{\n  height:34px;\n  border:1px solid rgba(216,176,92,.35);\n  background:#111722;\n  color:var(--gold);\n  font-weight:850;\n  outline:none;\n  padding:0 7px;\n  cursor:pointer;\n}\n\n/* board, redesigned flatter and cleaner */\n.boards{\n  display:grid;\n  gap:12px;\n  justify-content:center;\n}\n.boards.one{grid-template-columns:minmax(300px,min(74vmin,470px))}\n.boards.two,.boards.three,.boards.four{\n  grid-template-columns:repeat(2,minmax(260px,1fr));\n  width:min(94vw,820px);\n  margin-left:50%;\n  transform:translateX(-50%);\n}\n.boards.five,.boards.six{\n  grid-template-columns:repeat(3,minmax(220px,1fr));\n  width:min(96vw,940px);\n  margin-left:50%;\n  transform:translateX(-50%);\n}\n.board-shell{\n  padding:4px;\n  background:#0f141f;\n  border:1px solid rgba(216,176,92,.42);\n  box-shadow:0 0 22px rgba(0,0,0,.38),0 0 18px rgba(216,176,92,.045);\n}\n.board{\n  display:grid;\n  grid-template-columns:repeat(5,1fr);\n  gap:1px;\n  background:var(--grid);\n  border:1px solid var(--grid);\n  aspect-ratio:1/1;\n}\n.cell{\n  position:relative;\n  overflow:hidden;\n  border:0;\n  background:var(--cell);\n  color:var(--text);\n  font-size:clamp(9px,1.44vw,13px);\n  line-height:1.08;\n  font-weight:820;\n  text-align:center;\n  padding:5px;\n  cursor:pointer;\n  display:flex;\n  align-items:center;\n  justify-content:center;\n  user-select:none;\n  transition:transform .12s ease,filter .12s ease,box-shadow .12s ease,background .12s ease;\n}\n.cell:nth-child(even){background:var(--cell2)}\n.boards.two .cell,.boards.three .cell,.boards.four .cell{font-size:clamp(8px,1vw,11px)}\n.boards.five .cell,.boards.six .cell{font-size:clamp(7px,.75vw,9px)}\n.cell:hover{\n  transform:translateY(-1px);\n  filter:brightness(1.08);\n  box-shadow:inset 0 0 0 1px rgba(216,176,92,.50),0 0 10px rgba(216,176,92,.11);\n}\n.cell.free{\n  background:var(--purple)!important;\n  color:var(--gold);\n  font-style:italic;\n  cursor:default;\n  transform:none!important;\n}\n.cell.free:hover{filter:none;box-shadow:inset 0 0 0 1px rgba(216,176,92,.45)}\n.cell.marked{\n  background:linear-gradient(180deg,var(--green2),var(--green))!important;\n  color:#edfff5;\n  box-shadow:inset 0 0 14px rgba(255,255,255,.08),0 0 12px rgba(71,230,160,.16);\n  animation:markPop .22s ease;\n}\n.cell.marked::after{\n  content:\"\u2713\";\n  position:absolute;\n  right:5px;\n  bottom:0;\n  font-size:16px;\n  opacity:.34;\n}\n@keyframes markPop{\n  0%{transform:scale(.97)}\n  70%{transform:scale(1.035)}\n  100%{transform:scale(1)}\n}\n.cell.rolling:not(.free){animation:cellFlip .28s ease}\n@keyframes cellFlip{\n  0%{filter:brightness(.65);transform:translateY(3px)}\n  60%{filter:brightness(1.25);transform:translateY(-2px)}\n  100%{filter:brightness(1);transform:translateY(0)}\n}\n\n/* modal */\n.modal-backdrop{\n  position:fixed;\n  inset:0;\n  background:rgba(0,0,0,.68);\n  display:none;\n  align-items:center;\n  justify-content:center;\n  z-index:50;\n  padding:20px;\n}\n.modal-backdrop.show{display:flex;animation:fadeIn .16s ease}\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n.modal{\n  width:min(92vw,390px);\n  background:#101722;\n  border:1px solid rgba(216,176,92,.25);\n  padding:18px;\n  box-shadow:0 0 36px rgba(0,0,0,.55);\n  animation:modalIn .2s ease;\n}\n@keyframes modalIn{\n  from{transform:translateY(8px) scale(.98);opacity:0}\n  to{transform:translateY(0) scale(1);opacity:1}\n}\n.modal h2{margin:0 0 10px;color:var(--gold);font-size:30px;line-height:1}\n.modal p{color:var(--text);margin:8px 0;font-weight:720}\n.close{\n  margin-top:14px;\n  width:100%;\n  height:36px;\n  border:1px solid rgba(216,176,92,.35);\n  background:#14100a;\n  color:var(--gold);\n  font-weight:900;\n  cursor:pointer;\n}\n.bingo-modal .modal{text-align:center}\n.bingo-modal h2{\n  font-size:clamp(52px,10vw,86px);\n  animation:jackpot .72s ease-in-out infinite alternate;\n  text-shadow:0 0 16px var(--gold),0 0 32px var(--pink);\n}\n@keyframes jackpot{\n  from{transform:scale(1);filter:brightness(1)}\n  to{transform:scale(1.055);filter:brightness(1.28)}\n}\n.confetti{\n  position:fixed;\n  top:-20px;\n  font-size:18px;\n  z-index:60;\n  animation:fall 1.25s linear forwards;\n}\n@keyframes fall{to{transform:translateY(110vh) rotate(380deg);opacity:.2}}\n\n@media(max-width:760px){\n  .boards.two,.boards.three,.boards.four,.boards.five,.boards.six{\n    grid-template-columns:1fr;\n    width:min(94vw,500px);\n  }\n  .cell,.boards.two .cell,.boards.three .cell,.boards.four .cell,.boards.five .cell,.boards.six .cell{\n    font-size:clamp(9px,2.35vw,12px);\n  }\n}\n</style>\n</head>\n<body>\n  <div class=\"sky-item plane p1\"><svg viewBox=\"0 0 48 22\"><path d=\"M2 12h26L42 4l-6 8 6 8-14-8H2z\"></path><path d=\"M16 12 9 5M16 12 9 19\"></path></svg></div>\n  <div class=\"sky-item plane p2\"><svg viewBox=\"0 0 48 22\"><path d=\"M2 12h26L42 4l-6 8 6 8-14-8H2z\"></path><path d=\"M16 12 9 5M16 12 9 19\"></path></svg></div>\n  <div class=\"sky-item plane p3\"><svg viewBox=\"0 0 48 22\"><path d=\"M2 12h26L42 4l-6 8 6 8-14-8H2z\"></path><path d=\"M16 12 9 5M16 12 9 19\"></path></svg></div>\n  <div class=\"sky-item trail t1\"></div>\n  <div class=\"sky-item trail t2\"></div>\n  <div class=\"sky-item mini-bingo b1\"></div>\n  <div class=\"sky-item mini-bingo b2\"></div>\n  <div class=\"sky-item cloud c1\">BINGO</div>\n  <div class=\"sky-item cloud c2\">WOG</div>\n\n  <div class=\"app\">\n    <div class=\"header\">\n      <div class=\"logo-card\">\n        <div class=\"title\">Low Rank<span>Bingo</span></div>\n      </div>\n    </div>\n\n    <div class=\"toolbar\">\n      <button class=\"icon-btn\" title=\"Roll\" onclick=\"rollBoards()\">\n        <svg viewBox=\"0 0 24 24\"><rect x=\"4\" y=\"4\" width=\"16\" height=\"16\"></rect><circle cx=\"8\" cy=\"8\" r=\"1\"></circle><circle cx=\"16\" cy=\"8\" r=\"1\"></circle><circle cx=\"12\" cy=\"12\" r=\"1\"></circle><circle cx=\"8\" cy=\"16\" r=\"1\"></circle><circle cx=\"16\" cy=\"16\" r=\"1\"></circle></svg>\n      </button>\n      <button class=\"icon-btn\" title=\"Reset\" onclick=\"resetMarks()\">\n        <svg viewBox=\"0 0 24 24\"><path d=\"M4 12a8 8 0 1 0 3-6\"></path><path d=\"M4 4v6h6\"></path></svg>\n      </button>\n      <button class=\"icon-btn\" title=\"Rules\" onclick=\"openRules()\">\n        <svg viewBox=\"0 0 24 24\"><path d=\"M9.5 9a2.5 2.5 0 1 1 4.3 1.7c-1.2 1-1.8 1.5-1.8 3.1\"></path><path d=\"M12 18h.01\"></path><circle cx=\"12\" cy=\"12\" r=\"9\"></circle></svg>\n      </button>\n      <select class=\"board-select\" id=\"boardCount\" title=\"Boards\" onchange=\"setBoardCount(this.value)\">\n        <option value=\"1\">1 board</option>\n        <option value=\"2\">2 boards</option>\n        <option value=\"3\">3 boards</option>\n        <option value=\"4\">4 boards</option>\n        <option value=\"5\">5 boards</option>\n        <option value=\"6\">6 boards</option>\n      </select>\n    </div>\n\n    <div id=\"boards\" class=\"boards one\"></div>\n  </div>\n\n  <div id=\"rulesModal\" class=\"modal-backdrop\" onclick=\"closeRules(event)\">\n    <div class=\"modal\">\n      <h2>Rules</h2>\n      <p>\u2022 Click a square when it happens.</p>\n      <p>\u2022 Free space starts marked.</p>\n      <p>\u2022 5 in a row wins.</p>\n      <p>\u2022 Rows, columns, diagonals count.</p>\n      <button class=\"close\" onclick=\"hideRules()\">Close</button>\n    </div>\n  </div>\n\n  <div id=\"bingoModal\" class=\"modal-backdrop bingo-modal\" onclick=\"hideBingo()\">\n    <div class=\"modal\">\n      <h2>BINGO!</h2>\n      <p>jackpot hit</p>\n      <button class=\"close\" onclick=\"hideBingo()\">Close</button>\n    </div>\n  </div>\n\n<script>\nconst ITEMS = [\"\\\"add 5th gen aircrafts!\\\"\", \"DOGSHIT opinion or suggestion\", \"corny ass profile/pfp\", \"\\\"errrmm is all bvr so it's LAME\\\"\", \"chaff = flare\", \"thinks they're good\", \"nerf f14a or phoenix missiles\", \"compares wog to wt\", \"doesn't know any bfm/acm\", \"\\\"codes?\\\"\", \"add their favorite niche aircraft\", \"\\\"i have a life/whats wrong with low rank\\\"\", \"realized they have no image perms\", \"\\\"My rank ingame is higher\\\"\", \"extremely biased\", \"intentional rule breaking\", \"\\\"when update?\\\" bro the update is soon chilllll\", \"bitching about killstealing\", \"\\\"(decent plane) is so bad\\\"\", \"\\\"(premium plane) is p2w...\\\"\", \"\\\"add (insert nation) tree!\\\"\", \"can't lose their argument\", \"rants about russian aircrafts\", \"huge fuckass ego\"];\nlet boards=[]; let marked=[]; let boardCount=1; let rolling=false;\nfunction shuffle(arr){const a=[...arr];for(let i=a.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));[a[i],a[j]]=[a[j],a[i]];}return a;}\nfunction makeBoard(){const items=shuffle(ITEMS);const board=[];let idx=0;for(let i=0;i<25;i++){if(i===12)board.push(\"FREE SPACE\");else board.push(items[idx++]);}return board;}\nfunction classForCount(){if(boardCount===1)return\"one\";if(boardCount===2)return\"two\";if(boardCount===3)return\"three\";if(boardCount===4)return\"four\";if(boardCount===5)return\"five\";return\"six\";}\nfunction setBoardCount(n){boardCount=Math.max(1,Math.min(6,Number(n)));while(boards.length<boardCount){boards.push(makeBoard());marked.push(new Set([12]));}while(boards.length>boardCount){boards.pop();marked.pop();}render();}\nfunction render(){const root=document.getElementById(\"boards\");root.className=\"boards \"+classForCount();root.innerHTML=\"\";for(let b=0;b<boardCount;b++){const shell=document.createElement(\"div\");shell.className=\"board-shell\";const board=document.createElement(\"div\");board.className=\"board\";for(let i=0;i<25;i++){const cell=document.createElement(\"div\");cell.className=\"cell\";if(i===12)cell.classList.add(\"free\");if(marked[b].has(i))cell.classList.add(\"marked\");cell.textContent=boards[b][i];cell.onclick=()=>toggleCell(b,i);board.appendChild(cell);}shell.appendChild(board);root.appendChild(shell);}}\nfunction toggleCell(b,i){if(i===12||rolling)return;const root=document.getElementById(\"boards\");const boardEl=root.children[b].querySelector(\".board\");const cell=boardEl.children[i];if(marked[b].has(i)){marked[b].delete(i);cell.classList.remove(\"marked\");}else{marked[b].add(i);cell.classList.add(\"marked\");}if(hasBingo(marked[b]))showBingo();}\nfunction winLines(){const lines=[];for(let r=0;r<5;r++)lines.push([0,1,2,3,4].map(c=>r*5+c));for(let c=0;c<5;c++)lines.push([0,1,2,3,4].map(r=>r*5+c));lines.push([0,6,12,18,24]);lines.push([4,8,12,16,20]);return lines;}\nfunction hasBingo(set){return winLines().some(line=>line.every(i=>set.has(i)));}\nfunction rollBoards(){if(rolling)return;rolling=true;const allCells=()=>Array.from(document.querySelectorAll(\".cell:not(.free)\"));let steps=10;function spin(step){const tempBoards=Array.from({length:boardCount},()=>makeBoard());allCells().forEach((cell,idx)=>{const boardIndex=Math.floor(idx/24);const innerIndex=idx%24;const pool=tempBoards[boardIndex].filter((_,i)=>i!==12);cell.textContent=pool[innerIndex]||ITEMS[Math.floor(Math.random()*ITEMS.length)];cell.classList.remove(\"marked\");cell.classList.remove(\"rolling\");void cell.offsetWidth;cell.classList.add(\"rolling\");});if(step<steps){setTimeout(()=>spin(step+1),55+step*10);}else{boards=Array.from({length:boardCount},()=>makeBoard());marked=Array.from({length:boardCount},()=>new Set([12]));rolling=false;render();}}spin(0);}\nfunction resetMarks(){marked=Array.from({length:boardCount},()=>new Set([12]));render();}\nfunction openRules(){document.getElementById(\"rulesModal\").classList.add(\"show\")}function hideRules(){document.getElementById(\"rulesModal\").classList.remove(\"show\")}function closeRules(e){if(e.target.id===\"rulesModal\")hideRules()}function showBingo(){document.getElementById(\"bingoModal\").classList.add(\"show\");confettiBurst()}function hideBingo(){document.getElementById(\"bingoModal\").classList.remove(\"show\")}\nfunction confettiBurst(){const shapes=[\"\u2708\",\"\u2605\",\"\u25c6\",\"\u25cf\",\"B\",\"\u2713\"];const colors=[\"#d8b05c\",\"#d95772\",\"#47e6a0\",\"#61c8e8\",\"#ffffff\"];for(let i=0;i<32;i++){const s=document.createElement(\"div\");s.className=\"confetti\";s.textContent=shapes[Math.floor(Math.random()*shapes.length)];s.style.left=Math.random()*100+\"vw\";s.style.color=colors[Math.floor(Math.random()*colors.length)];s.style.animationDelay=Math.random()*.15+\"s\";document.body.appendChild(s);setTimeout(()=>s.remove(),1500);}}\ndocument.addEventListener(\"keydown\",e=>{if(e.key===\"Escape\"){hideRules();hideBingo();}});\nboards=[makeBoard()];marked=[new Set([12])];render();\n</script>\n</body>\n</html>\n"

components.html(html, height=900, scrolling=True)
